# --- Core tools (used by supervisor and core assistant) ---
@tool
def execute_sql(query: str) -> str:
    """Execute a guarded SQL query against the data warehouse."""
    return f"Mock SQL result for: {query[:50]}..."

@tool
def run_cypher(query: str) -> str:
    """Execute a Cypher query against Neo4j."""
    return f"Mock Cypher result for: {query[:50]}..."

@tool
def query_knowledge_graph(nl_question: str) -> str:
    """Answer a natural language question using the knowledge graph."""
    return f"Knowledge graph answer for: {nl_question}"

@tool
def search_glossary(term: str) -> str:
    """Search the governed glossary for a term."""
    return f"Glossary entry for '{term}': definition, tables, rules."

# --- Ontology tools ---
@tool
def query_ontology(sparql: str) -> str:
    """Execute a read-only SPARQL query against GraphDB."""
    return f"SPARQL result: {sparql[:50]}..."

@tool
def expand_ontology(class_uri: str) -> str:
    """Get subclasses and superclasses for a FIBO class."""
    return f"Subclasses of {class_uri}: [Asset, Equity, ...]"

@tool
def reason_about_class(class_uri: str) -> str:
    """Run HermiT reasoner to check consistency."""
    return f"Class {class_uri} is consistent (HermiT)."

# --- Graph analytics tools ---
@tool
def page_rank(label: str) -> str:
    """Compute PageRank for nodes with the given label."""
    return f"PageRank results for {label}: top nodes..."

@tool
def find_communities(label: str) -> str:
    """Find communities using Louvain on nodes with the given label."""
    return f"Community detection for {label}: 3 communities found."

@tool
def graph_rag_query(question: str) -> str:
    """Hybrid GraphRAG retrieval (vector + graph)."""
    return f"GraphRAG answer: {question}"

# --- Document tools ---
@tool
def ingest_document(text: str) -> str:
    """Ingest a document, extract mentions, and publish to GraphDB."""
    return "Document ingested: 5 mentions, 2 resolved."

@tool
def resolve_mentions(doc_id: str) -> str:
    """Resolve mentions in a document against the glossary."""
    return f"Resolved mentions for doc {doc_id}"

import uuid
session_id = str(uuid.uuid4())
config = {"configurable": {"thread_id": session_id}}

# Test 1: simple SQL question -> supervisor handles directly
inputs = {"messages": [HumanMessage(content="What is the total notional value of all trades today?")]}
print("User: What is the total notional value of all trades today?")
for output in supervisor_app.stream(inputs, config, stream_mode="values"):
    pass  # we can inspect intermediate steps if desired
final_state = supervisor_app.get_state(config).values
print("Assistant:", final_state["final_output"])

state = supervisor_app.get_state(config)
for msg in state.values["messages"]:
    if hasattr(msg, "content") and msg.content:
        print(f"{msg.type.upper()}: {msg.content[:150]}...")
